INSERT INTO texts (title, hanzi, pinyin, translation, hsk_level) VALUES
(
    'Моя семья',
    '我家有五个人:爸爸、妈妈、哥哥、姐姐和我。爸爸是医生,妈妈是老师。哥哥今年二十岁,他是大学生。姐姐工作,她很忙。我最小,我是中学生。我爱我的家人。',
    'Wǒ jiā yǒu wǔ gè rén: bàba, māma, gēge, jiějie hé wǒ. Bàba shì yīshēng, māma shì lǎoshī. Gēge jīnnián èrshí suì, tā shì dàxuéshēng. Jiějie gōngzuò, tā hěn máng. Wǒ zuì xiǎo, wǒ shì zhōngxuéshēng. Wǒ ài wǒ de jiārén.',
    'В моей семье пять человек: папа, мама, старший брат, старшая сестра и я. Папа — врач, мама — учительница. Старшему брату в этом году двадцать лет, он студент университета. Старшая сестра работает, она очень занята. Я самый младший, я школьник. Я люблю свою семью.',
    1
),
(
    'Моя школа',
    '我的学校很大,也很漂亮。学校里有很多树和花。我每天八点上课,十二点吃午饭,下午四点放学。我喜欢我的老师,他们都很好。我也喜欢我的同学。',
    'Wǒ de xuéxiào hěn dà, yě hěn piàoliang. Xuéxiào lǐ yǒu hěn duō shù hé huā. Wǒ měitiān bā diǎn shàngkè, shí''èr diǎn chī wǔfàn, xiàwǔ sì diǎn fàngxué. Wǒ xǐhuan wǒ de lǎoshī, tāmen dōu hěn hǎo. Wǒ yě xǐhuan wǒ de tóngxué.',
    'Моя школа очень большая и очень красивая. В школе много деревьев и цветов. Я каждый день начинаю уроки в восемь часов, обедаю в двенадцать, а заканчиваю учиться в четыре часа дня. Мне нравятся мои учителя, они все очень хорошие. Мне также нравятся мои одноклассники.',
    1
),
(
    'Мой любимый цвет и еда',
    '我叫小英。我最喜欢的颜色是蓝色。我的衣服和书包都是蓝色的。我也很喜欢吃中国菜,特别是米饭和鱼。我不喜欢喝咖啡,我喜欢喝茶。周末我常常和家人一起吃饭。',
    'Wǒ jiào Xiǎo Yīng. Wǒ zuì xǐhuan de yánsè shì lánsè. Wǒ de yīfu hé shūbāo dōu shì lánsè de. Wǒ yě hěn xǐhuan chī Zhōngguó cài, tèbié shì mǐfàn hé yú. Wǒ bù xǐhuan hē kāfēi, wǒ xǐhuan hē chá. Zhōumò wǒ chángcháng hé jiārén yìqǐ chīfàn.',
    'Меня зовут Сяо Ин. Мой любимый цвет — синий. Моя одежда и рюкзак синего цвета. Мне также очень нравится есть китайскую еду, особенно рис и рыбу. Я не люблю пить кофе, я люблю пить чай. По выходным я часто ем вместе с семьёй.',
    1
),
(
    'В ресторане',
    '今天晚上我和朋友去饭店吃饭。饭店的菜很好吃,也不贵。我点了一个鸡蛋汤和一盘炒饭,朋友点了面条。我们喝了果汁,没有喝酒。吃完饭,我们一起走回家。',
    'Jīntiān wǎnshang wǒ hé péngyou qù fàndiàn chīfàn. Fàndiàn de cài hěn hǎochī, yě bú guì. Wǒ diǎnle yí gè jīdàntāng hé yì pán chǎofàn, péngyou diǎnle miàntiáo. Wǒmen hēle guǒzhī, méiyǒu hē jiǔ. Chīwán fàn, wǒmen yìqǐ zǒu huí jiā.',
    'Сегодня вечером я с другом пошёл в ресторан поесть. Еда в ресторане очень вкусная и недорогая. Я заказал яичный суп и тарелку жареного риса, друг заказал лапшу. Мы пили сок, не пили алкоголь. Поев, мы вместе пошли домой пешком.',
    1
),
(
    'Мой дом',
    '我家不大,但是很舒服。家里有三个房间:我的房间、爸爸妈妈的房间和客厅。我的房间里有一张床、一个桌子和很多书。我喜欢在自己的房间里看书、听音乐。',
    'Wǒ jiā bú dà, dànshì hěn shūfu. Jiā lǐ yǒu sān gè fángjiān: wǒ de fángjiān, bàba māma de fángjiān hé kètīng. Wǒ de fángjiān lǐ yǒu yì zhāng chuáng, yí gè zhuōzi hé hěn duō shū. Wǒ xǐhuan zài zìjǐ de fángjiān lǐ kànshū, tīng yīnyuè.',
    'Мой дом небольшой, но очень уютный. Дома есть три комнаты: моя комната, комната родителей и гостиная. В моей комнате есть кровать, стол и много книг. Мне нравится в своей комнате читать книги и слушать музыку.',
    1
),
(
    'Поездка на автобусе',
    '昨天我坐公共汽车去朋友家。因为路上车太多,所以我等了很长时间。上车以后,车里的人也很多,我没有找到座位,只能站着。虽然有点累,但是能和朋友见面,我还是很高兴。',
    'Zuótiān wǒ zuò gōnggòng qìchē qù péngyou jiā. Yīnwèi lùshang chē tài duō, suǒyǐ wǒ děngle hěn cháng shíjiān. Shàngchē yǐhòu, chē lǐ de rén yě hěn duō, wǒ méiyǒu zhǎodào zuòwèi, zhǐ néng zhànzhe. Suīrán yǒudiǎn lèi, dànshì néng hé péngyou jiànmiàn, wǒ háishi hěn gāoxìng.',
    'Вчера я поехал(а) на автобусе к другу. Так как на дороге было слишком много машин, мне пришлось долго ждать. После посадки в автобус людей внутри тоже было много, я не нашёл(нашла) место и мог(ла) только стоять. Хотя я немного устал(а), но всё равно был(а) рад(а), что смог(ла) встретиться с другом.',
    2
),
(
    'День рождения друга',
    '上个星期是我朋友的生日。我们几个同学一起给他准备了一个惊喜派对。我们买了蛋糕、水果和饮料,还给他买了一份小礼物。他看到我们的时候非常惊讶,也非常开心。我们一起唱歌、吃蛋糕,玩儿到很晚才回家。',
    'Shàng gè xīngqī shì wǒ péngyou de shēngrì. Wǒmen jǐ gè tóngxué yìqǐ gěi tā zhǔnbèile yí gè jīngxǐ pàiduì. Wǒmen mǎile dàngāo, shuǐguǒ hé yǐnliào, hái gěi tā mǎile yí fèn xiǎo lǐwù. Tā kàndào wǒmen de shíhou fēicháng jīngyà, yě fēicháng kāixīn. Wǒmen yìqǐ chànggē, chī dàngāo, wánr dào hěn wǎn cái huí jiā.',
    'На прошлой неделе был день рождения моего друга. Несколько наших одноклассников вместе подготовили ему вечеринку-сюрприз. Мы купили торт, фрукты и напитки, а ещё купили ему небольшой подарок. Когда он нас увидел, он был очень удивлён и очень рад. Мы вместе пели песни, ели торт и веселились допоздна, прежде чем разойтись по домам.',
    2
),
(
    'В больнице',
    '前几天我感冒了,头疼,还发烧,所以我去医院看医生。医生给我检查以后,说没有大问题,只要多喝水、多休息就可以了。他给我开了一些药,让我一天吃三次。吃了两天药以后,我觉得好多了。',
    'Qián jǐ tiān wǒ gǎnmào le, tóuténg, hái fāshāo, suǒyǐ wǒ qù yīyuàn kàn yīshēng. Yīshēng gěi wǒ jiǎnchá yǐhòu, shuō méiyǒu dà wèntí, zhǐyào duō hē shuǐ, duō xiūxi jiù kěyǐ le. Tā gěi wǒ kāile yìxiē yào, ràng wǒ yì tiān chī sān cì. Chīle liǎng tiān yào yǐhòu, wǒ juéde hǎo duō le.',
    'Несколько дней назад я простудился(лась), болела голова и была температура, поэтому я пошёл(пошла) в больницу к врачу. После осмотра врач сказал, что серьёзных проблем нет, нужно только больше пить воды и больше отдыхать. Он выписал мне лекарство, велел принимать три раза в день. После двух дней приёма лекарства мне стало намного лучше.',
    2
),
(
    'Спорт и здоровье',
    '我以前不太喜欢运动,身体也不太好,常常生病。后来,我开始每天早上跑步,周末还去打篮球。三个月以后,我发现自己身体好多了,也很少感冒了。现在运动已经成了我生活中很重要的一部分。',
    'Wǒ yǐqián bú tài xǐhuan yùndòng, shēntǐ yě bú tài hǎo, chángcháng shēngbìng. Hòulái, wǒ kāishǐ měitiān zǎoshang pǎobù, zhōumò hái qù dǎ lánqiú. Sān gè yuè yǐhòu, wǒ fāxiàn zìjǐ shēntǐ hǎo duō le, yě hěn shǎo gǎnmào le. Xiànzài yùndòng yǐjīng chéngle wǒ shēnghuó zhōng hěn zhòngyào de yí bùfen.',
    'Раньше я не очень любил(а) спорт, и здоровье у меня было не очень хорошее, я часто болел(а). Позже я начал(а) каждое утро бегать, а по выходным ещё играть в баскетбол. Через три месяца я обнаружил(а), что моё здоровье стало намного лучше, и я редко простужаюсь. Сейчас спорт уже стал очень важной частью моей жизни.',
    2
),
(
    'Эта зима',
    '今年冬天比去年冷得多,已经下了好几场雪。路上很滑,人们出门都要穿得很厚。虽然天气很冷,但是孩子们还是很喜欢在雪地里玩儿,堆雪人、打雪仗。我也很久没有看到这么大的雪了,觉得非常美丽。',
    'Jīnnián dōngtiān bǐ qùnián lěng de duō, yǐjīng xiàle hǎo jǐ chǎng xuě. Lùshang hěn huá, rénmen chūmén dōu yào chuān de hěn hòu. Suīrán tiānqì hěn lěng, dànshì háizimen háishi hěn xǐhuan zài xuědì lǐ wánr, duī xuěrén, dǎ xuězhàng. Wǒ yě hěn jiǔ méiyǒu kàndào zhème dà de xuě le, juéde fēicháng měilì.',
    'Этой зимой намного холоднее, чем в прошлом году, уже прошло несколько снегопадов. Дороги очень скользкие, выходя из дома, людям приходится одеваться очень тепло. Хотя погода очень холодная, дети всё равно очень любят играть в снегу, лепить снеговиков, играть в снежки. Я тоже давно не видел(а) такого сильного снега и считаю его очень красивым.',
    2
),
(
    'Путешествие в горы',
    '上个月,我和几个朋友决定去爬山,放松一下平时紧张的生活。我们选择了一座离城市不远的山,风景非常美丽。爬到山顶的时候,虽然又累又渴,但是看到眼前壮观的景色,所有的疲劳都消失了。我们在山顶上拍了很多照片,还野餐了一顿。这次旅行让我明白,有时候离开城市,亲近大自然,是缓解压力最好的方式之一。',
    'Shàng gè yuè, wǒ hé jǐ gè péngyou juédìng qù páshān, fàngsōng yíxià píngshí jǐnzhāng de shēnghuó. Wǒmen xuǎnzéle yí zuò lí chéngshì bù yuǎn de shān, fēngjǐng fēicháng měilì. Pá dào shāndǐng de shíhou, suīrán yòu lèi yòu kě, dànshì kàndào yǎnqián zhuàngguān de jǐngsè, suǒyǒu de píláo dōu xiāoshī le. Wǒmen zài shāndǐng shàng pāile hěn duō zhàopiàn, hái yěcānle yí dùn. Zhè cì lǚxíng ràng wǒ míngbai, yǒu shíhou líkāi chéngshì, qīnjìn dà zìrán, shì huǎnjiě yālì zuì hǎo de fāngshì zhī yī.',
    'В прошлом месяце мы с несколькими друзьями решили пойти в поход в горы, чтобы немного расслабиться от напряжённой повседневной жизни. Мы выбрали гору неподалёку от города, с очень красивым пейзажем. Когда мы поднялись на вершину, хотя и устали, и хотели пить, но увидев перед собой величественный вид, вся усталость исчезла. Мы сделали на вершине много фотографий и ещё устроили пикник. Это путешествие дало мне понять, что иногда покинуть город и приблизиться к природе — один из лучших способов снять стресс.',
    3
),
(
    'Мой сосед по комнате',
    '我的室友是一个非常有意思的人。他来自一个南方的小城市,说话带着一点儿口音,但是普通话说得很清楚。他学的专业是计算机,每天花很多时间在电脑前写程序。虽然他很忙,但是他从来不会忘记打扫房间、洗衣服。我们两个人的爱好完全不同,他喜欢安静地看书,我喜欢和朋友一起出去玩儿,不过我们相处得很好,已经成了很好的朋友。',
    'Wǒ de shìyǒu shì yí gè fēicháng yǒuyìsi de rén. Tā láizì yí gè nánfāng de xiǎo chéngshì, shuōhuà dàizhe yìdiǎnr kǒuyīn, dànshì pǔtōnghuà shuō de hěn qīngchu. Tā xué de zhuānyè shì jìsuànjī, měitiān huā hěn duō shíjiān zài diànnǎo qián xiě chéngxù. Suīrán tā hěn máng, dànshì tā cónglái bú huì wàngjì dǎsǎo fángjiān, xǐ yīfu. Wǒmen liǎng gè rén de àihào wánquán bùtóng, tā xǐhuan ānjìng de kànshū, wǒ xǐhuan hé péngyou yìqǐ chūqù wánr, búguò wǒmen xiāngchǔ de hěn hǎo, yǐjīng chéngle hěn hǎo de péngyou.',
    'Мой сосед по комнате — очень интересный человек. Он родом из небольшого города на юге, говорит с небольшим акцентом, но на путунхуа говорит очень чётко. Он изучает специальность «компьютерные науки», каждый день проводит много времени перед компьютером, пишет программы. Хотя он очень занят, он никогда не забывает убираться в комнате и стирать одежду. Наши с ним увлечения совершенно разные: он любит спокойно читать книги, а я люблю выходить куда-то с друзьями, но мы хорошо ладим и уже стали хорошими друзьями.',
    3
),
(
    'Учим китайский язык',
    '我学习汉语已经两年了。刚开始的时候,我觉得汉字特别难写,发音也很难掌握,尤其是声调,常常说错。后来,我的老师告诉我,学语言最重要的是多听、多说,不要害怕犯错误。从那以后,我每天都听中文歌、看中文电视剧,还常常跟中国朋友聊天。慢慢地,我的汉语水平提高了不少,现在我已经可以用汉语跟朋友聊很多话题了。',
    'Wǒ xuéxí Hànyǔ yǐjīng liǎng nián le. Gāng kāishǐ de shíhou, wǒ juéde Hànzì tèbié nán xiě, fāyīn yě hěn nán zhǎngwò, yóuqí shì shēngdiào, chángcháng shuōcuò. Hòulái, wǒ de lǎoshī gàosu wǒ, xué yǔyán zuì zhòngyào de shì duō tīng, duō shuō, búyào hàipà fàn cuòwù. Cóng nà yǐhòu, wǒ měitiān dōu tīng Zhōngwén gē, kàn Zhōngwén diànshìjù, hái chángcháng gēn Zhōngguó péngyou liáotiān. Mànmàn de, wǒ de Hànyǔ shuǐpíng tígāole bù shǎo, xiànzài wǒ yǐjīng kěyǐ yòng Hànyǔ gēn péngyou liáo hěn duō huàtí le.',
    'Я изучаю китайский язык уже два года. Когда я только начинал(а), мне казалось, что иероглифы особенно трудно писать, а произношение тоже трудно освоить, особенно тоны — я часто произносил(а) их неправильно. Позже мой учитель сказал мне, что самое важное в изучении языка — это больше слушать, больше говорить и не бояться ошибок. С тех пор я каждый день слушаю китайские песни, смотрю китайские сериалы, а ещё часто болтаю с китайскими друзьями. Постепенно мой уровень китайского значительно вырос, и теперь я уже могу обсуждать с друзьями множество тем на китайском.',
    3
),
(
    'Праздник Весны',
    '春节是中国最重要的传统节日,也叫农历新年。每年春节前,不管人们在哪里工作、生活,都会想办法回家和家人团聚。除夕晚上,一家人会一起吃年夜饭,饭桌上有鱼、饺子等很多好吃的菜。吃完饭以后,大家会一起看春节联欢晚会,聊天到很晚。孩子们最喜欢的,就是可以收到长辈给的红包。春节期间,大街小巷都挂满了红灯笼,到处充满了热闹和喜庆的气氛。',
    'Chūnjié shì Zhōngguó zuì zhòngyào de chuántǒng jiérì, yě jiào nónglì xīnnián. Měinián Chūnjié qián, bùguǎn rénmen zài nǎlǐ gōngzuò, shēnghuó, dōu huì xiǎng bànfǎ huí jiā hé jiārén tuánjù. Chúxī wǎnshang, yìjiā rén huì yìqǐ chī niányèfàn, fànzhuō shàng yǒu yú, jiǎozi děng hěn duō hǎochī de cài. Chīwán fàn yǐhòu, dàjiā huì yìqǐ kàn Chūnjié Liánhuān Wǎnhuì, liáotiān dào hěn wǎn. Háizimen zuì xǐhuan de, jiùshì kěyǐ shōu dào zhǎngbèi gěi de hóngbāo. Chūnjié qījiān, dàjiē xiǎoxiàng dōu guà mǎnle hóng dēnglong, dàochù chōngmǎnle rènao hé xǐqìng de qìfēn.',
    'Праздник Весны — самый важный традиционный праздник в Китае, его также называют Новым годом по лунному календарю. Каждый год перед праздником, где бы люди ни работали и ни жили, они стараются найти способ вернуться домой и собраться с семьёй. Вечером в канун Нового года вся семья вместе ест новогодний ужин, на столе есть рыба, пельмени и много других вкусных блюд. После ужина все вместе смотрят новогодний праздничный концерт, разговаривают допоздна. Больше всего дети любят получать красные конверты от старших. В дни праздника все улицы и переулки увешаны красными фонариками, всюду царит оживлённая и праздничная атмосфера.',
    3
),
(
    'Домашние животные',
    '现在越来越多的人喜欢养宠物,尤其是猫和狗。养宠物不仅可以给生活增加乐趣,还能减轻压力。我家也养了一只小狗,它非常聪明,也很听话。每天下班回家,看到它摇着尾巴跑过来迎接我,一天的疲劳好像都消失了。当然,养宠物也需要负责任,要按时喂食、带它去看兽医、每天陪它散步。虽然有时候会觉得辛苦,但是看到它健康快乐地成长,我觉得一切都是值得的。',
    'Xiànzài yuè lái yuè duō de rén xǐhuan yǎng chǒngwù, yóuqí shì māo hé gǒu. Yǎng chǒngwù bùjǐn kěyǐ gěi shēnghuó zēngjiā lèqù, hái néng jiǎnqīng yālì. Wǒ jiā yě yǎngle yì zhī xiǎo gǒu, tā fēicháng cōngming, yě hěn tīnghuà. Měitiān xiàbān huí jiā, kàndào tā yáozhe wěiba pǎo guòlái yíngjiē wǒ, yì tiān de píláo hǎoxiàng dōu xiāoshī le. Dāngrán, yǎng chǒngwù yě xūyào fùzérèn, yào ànshí wèishí, dài tā qù kàn shòuyī, měitiān péi tā sànbù. Suīrán yǒu shíhou huì juéde xīnkǔ, dànshì kàndào tā jiànkāng kuàilè de chéngzhǎng, wǒ juéde yíqiè dōu shì zhíde de.',
    'Сейчас всё больше людей любят заводить домашних животных, особенно кошек и собак. Содержание питомца не только добавляет радости в жизнь, но и снижает стресс. У меня дома тоже есть маленькая собака, она очень умная и послушная. Каждый день, возвращаясь домой с работы, вижу, как она подбегает ко мне, виляя хвостом, встречает меня — и вся усталость за день будто исчезает. Конечно, содержание питомца требует ответственности: нужно вовремя кормить, водить к ветеринару, каждый день гулять с ним. Хотя иногда это кажется тяжёлым, но видя, как она растёт здоровой и счастливой, я считаю, что всё это того стоит.',
    3
),
(
    'Плюсы и минусы работы из дома',
    '近几年,远程办公越来越普遍,很多公司允许员工在家工作。在家办公的好处显而易见:员工可以节省上下班的时间,自由安排工作节奏,也能更好地照顾家庭。然而,这种工作方式也带来了新的挑战。有些人反映,在家工作容易分心,工作和生活的界限变得模糊,反而降低了效率。此外,长期缺乏面对面的交流,也可能影响团队合作和沟通效果。因此,如何在灵活性和效率之间找到平衡,是企业和员工都需要认真思考的问题。',
    'Jìn jǐ nián, yuǎnchéng bàngōng yuè lái yuè pǔbiàn, hěn duō gōngsī yǔnxǔ yuángōng zài jiā gōngzuò. Zài jiā bàngōng de hǎochù xiǎn''éryìjiàn: yuángōng kěyǐ jiéshěng shàngxiàbān de shíjiān, zìyóu ānpái gōngzuò jiézòu, yě néng gèng hǎo de zhàogù jiātíng. Rán''ér, zhè zhǒng gōngzuò fāngshì yě dàiláile xīn de tiǎozhàn. Yǒuxiē rén fǎnyìng, zài jiā gōngzuò róngyì fēnxīn, gōngzuò hé shēnghuó de jièxiàn biàn de móhu, fǎn''ér jiàngdīle xiàolǜ. Cǐwài, chángqī quēfá miànduìmiàn de jiāoliú, yě kěnéng yǐngxiǎng tuánduì hézuò hé gōutōng xiàoguǒ. Yīncǐ, rúhé zài línghuóxìng hé xiàolǜ zhījiān zhǎodào pínghéng, shì qǐyè hé yuángōng dōu xūyào rènzhēn sīkǎo de wèntí.',
    'В последние годы удалённая работа становится всё более распространённой, многие компании разрешают сотрудникам работать из дома. Преимущества работы из дома очевидны: сотрудники могут сэкономить время на дорогу на работу и обратно, свободно распределять рабочий ритм, а также лучше заботиться о семье. Однако такой способ работы приносит и новые сложности. Некоторые отмечают, что дома легко отвлечься, граница между работой и личной жизнью становится размытой, что снижает эффективность. Кроме того, долгое отсутствие личного общения может повлиять на командную работу и качество коммуникации. Поэтому вопрос о том, как найти баланс между гибкостью и эффективностью, требует серьёзного размышления как со стороны компаний, так и сотрудников.',
    4
),
(
    'Значение дружбы',
    '人的一生中会遇到很多人,但真正能称得上朋友的却不多。真正的朋友,不是在你成功时锦上添花的人,而是在你失败、遇到困难时,依然愿意陪在你身边、给你支持的人。友谊需要用心经营,需要彼此的信任和理解,也需要在对方需要的时候伸出援手。随着年龄的增长,我们会发现,能一直陪伴自己走下去的朋友越来越少,也因此越来越珍贵。所以,我们更应该珍惜眼前的友谊,用心去维护这份来之不易的感情。',
    'Rén de yìshēng zhōng huì yùdào hěn duō rén, dàn zhēnzhèng néng chēngdéshàng péngyou de què bù duō. Zhēnzhèng de péngyou, bú shì zài nǐ chénggōng shí jǐnshàngtiānhuā de rén, ér shì zài nǐ shībài, yùdào kùnnan shí, yīrán yuànyì péi zài nǐ shēnbiān, gěi nǐ zhīchí de rén. Yǒuyì xūyào yòngxīn jīngyíng, xūyào bǐcǐ de xìnrèn hé lǐjiě, yě xūyào zài duìfāng xūyào de shíhou shēnchū yuánshǒu. Suízhe niánlíng de zēngzhǎng, wǒmen huì fāxiàn, néng yìzhí péibàn zìjǐ zǒu xiàqù de péngyou yuè lái yuè shǎo, yě yīncǐ yuè lái yuè zhēnguì. Suǒyǐ, wǒmen gèng yīnggāi zhēnxī yǎnqián de yǒuyì, yòngxīn qù wéihù zhè fèn láizhībùyì de gǎnqíng.',
    'В жизни человека встречается много людей, но по-настоящему друзьями можно назвать немногих. Настоящий друг — это не тот, кто украшает твой успех, а тот, кто в твоей неудаче или трудностях по-прежнему готов быть рядом и поддерживать тебя. Дружбу нужно выстраивать с душой, она требует взаимного доверия и понимания, а также готовности протянуть руку помощи, когда другому это нужно. С возрастом мы обнаруживаем, что друзей, готовых сопровождать нас всю жизнь, становится всё меньше, и поэтому они становятся всё ценнее. Поэтому нам стоит ещё больше дорожить дружбой, которая у нас есть, и бережно поддерживать это непросто доставшееся чувство.',
    4
),
(
    'Городская и деревенская жизнь',
    '关于城市生活和农村生活,人们一直有不同的看法。喜欢城市生活的人认为,城市交通便利,医疗和教育资源丰富,工作机会也更多。而喜欢农村生活的人则认为,农村空气清新,节奏缓慢,邻里关系也更加亲密。近年来,随着互联网的发展,越来越多的年轻人开始选择离开大城市,回到农村生活和工作。他们通过网络平台销售农产品,既能享受田园生活,又不会与外界脱节。这种新的生活方式,正在悄悄地改变着人们对城市和农村的传统印象。',
    'Guānyú chéngshì shēnghuó hé nóngcūn shēnghuó, rénmen yìzhí yǒu bùtóng de kànfǎ. Xǐhuan chéngshì shēnghuó de rén rènwéi, chéngshì jiāotōng biànlì, yīliáo hé jiàoyù zīyuán fēngfù, gōngzuò jīhuì yě gèng duō. Ér xǐhuan nóngcūn shēnghuó de rén zé rènwéi, nóngcūn kōngqì qīngxīn, jiézòu huǎnmàn, línlǐ guānxì yě gèngjiā qīnmì. Jìnnián lái, suízhe hùliánwǎng de fāzhǎn, yuè lái yuè duō de niánqīngrén kāishǐ xuǎnzé líkāi dà chéngshì, huídào nóngcūn shēnghuó hé gōngzuò. Tāmen tōngguò wǎngluò píngtái xiāoshòu nóngchǎnpǐn, jì néng xiǎngshòu tiányuán shēnghuó, yòu bú huì yǔ wàijiè tuōjié. Zhè zhǒng xīn de shēnghuó fāngshì, zhèngzài qiāoqiāo de gǎibiànzhe rénmen duì chéngshì hé nóngcūn de chuántǒng yìnxiàng.',
    'Относительно городской и сельской жизни у людей всегда были разные взгляды. Те, кому нравится городская жизнь, считают, что в городе удобный транспорт, богатые медицинские и образовательные ресурсы и больше возможностей для работы. А те, кому нравится деревенская жизнь, считают, что в деревне чистый воздух, неспешный ритм и более тесные отношения с соседями. В последние годы, с развитием интернета, всё больше молодых людей начинают выбирать отъезд из больших городов и возвращение в деревню для жизни и работы. Они продают сельскохозяйственную продукцию через интернет-платформы, что позволяет наслаждаться сельской жизнью, не теряя связи с внешним миром. Этот новый образ жизни постепенно меняет традиционные представления людей о городе и деревне.',
    4
),
(
    'Использование смартфонов среди молодёжи',
    '智能手机已经成为现代人生活中不可缺少的工具,尤其是在年轻人中间,几乎人手一部。手机不仅可以用来打电话、发信息,还可以购物、学习、娱乐,功能十分强大。然而,过度使用手机也带来了不少问题。有调查显示,不少年轻人每天花在手机上的时间超过五个小时,这不仅影响视力,还会导致注意力下降,甚至影响正常的人际交往。专家建议,年轻人应该合理安排使用手机的时间,多参加户外活动,多与家人朋友面对面交流,这样才能保持身心健康。',
    'Zhìnéng shǒujī yǐjīng chéngwéi xiàndài rén shēnghuó zhōng bùkě quēshǎo de gōngjù, yóuqí shì zài niánqīngrén zhōngjiān, jīhū rénshǒu yí bù. Shǒujī bùjǐn kěyǐ yònglái dǎ diànhuà, fā xìnxī, hái kěyǐ gòuwù, xuéxí, yúlè, gōngnéng shífēn qiángdà. Rán''ér, guòdù shǐyòng shǒujī yě dàiláile bù shǎo wèntí. Yǒu diàochá xiǎnshì, bù shǎo niánqīngrén měitiān huā zài shǒujī shàng de shíjiān chāoguò wǔ gè xiǎoshí, zhè bùjǐn yǐngxiǎng shìlì, hái huì dǎozhì zhùyìlì xiàjiàng, shènzhì yǐngxiǎng zhèngcháng de rénjì jiāowǎng. Zhuānjiā jiànyì, niánqīngrén yīnggāi hélǐ ānpái shǐyòng shǒujī de shíjiān, duō cānjiā hùwài huódòng, duō yǔ jiārén péngyou miànduìmiàn jiāoliú, zhèyàng cáinéng bǎochí shēnxīn jiànkāng.',
    'Смартфон уже стал незаменимым инструментом в жизни современного человека, особенно среди молодёжи, где он есть почти у каждого. Телефон можно использовать не только для звонков и сообщений, но и для покупок, учёбы, развлечений — его функции очень широки. Однако чрезмерное использование телефона тоже приносит немало проблем. Опросы показывают, что многие молодые люди тратят на телефон более пяти часов в день, что не только влияет на зрение, но и приводит к снижению концентрации внимания и даже влияет на нормальное общение с людьми. Эксперты советуют молодым людям разумно распределять время использования телефона, больше участвовать в активностях на свежем воздухе, больше общаться лицом к лицу с семьёй и друзьями — только так можно сохранить физическое и психическое здоровье.',
    4
),
(
    'Как справляться со стрессом',
    '现代生活节奏越来越快,不管是学生还是上班族,都或多或少地承受着压力。适当的压力可以让人保持动力,但是长期处于高压状态,则可能对身心健康造成负面影响。面对压力,不同的人有不同的应对方式:有人选择运动来释放情绪,有人喜欢和朋友聊天倾诉,也有人通过听音乐、看电影来放松自己。心理专家指出,学会正确地面对压力,而不是一味逃避,才是解决问题的关键。当压力实在难以承受时,及时寻求专业人士的帮助,也是非常必要的。',
    'Xiàndài shēnghuó jiézòu yuè lái yuè kuài, bùguǎn shì xuésheng háishi shàngbānzú, dōu huòduōhuòshǎo de chéngshòuzhe yālì. Shìdàng de yālì kěyǐ ràng rén bǎochí dònglì, dànshì chángqī chǔyú gāoyā zhuàngtài, zé kěnéng duì shēnxīn jiànkāng zàochéng fùmiàn yǐngxiǎng. Miànduì yālì, bùtóng de rén yǒu bùtóng de yìngduì fāngshì: yǒurén xuǎnzé yùndòng lái shìfàng qíngxù, yǒurén xǐhuan hé péngyou liáotiān qīngsù, yě yǒurén tōngguò tīng yīnyuè, kàn diànyǐng lái fàngsōng zìjǐ. Xīnlǐ zhuānjiā zhǐchū, xuéhuì zhèngquè de miànduì yālì, ér bú shì yíwèi táobì, cái shì jiějué wèntí de guānjiàn. Dāng yālì shízài nányǐ chéngshòu shí, jíshí xúnqiú zhuānyè rénshì de bāngzhù, yě shì fēicháng bìyào de.',
    'Ритм современной жизни становится всё быстрее, и как студенты, так и работающие люди в той или иной степени испытывают стресс. Умеренный стресс может поддерживать мотивацию, но длительное пребывание в состоянии высокого напряжения может негативно сказаться на физическом и психическом здоровье. Сталкиваясь со стрессом, разные люди справляются по-разному: кто-то выбирает спорт, чтобы выпустить эмоции, кто-то любит поговорить и излить душу другу, а кто-то расслабляется, слушая музыку или смотря фильмы. Психологи указывают, что научиться правильно сталкиваться со стрессом, а не просто избегать его, — вот ключ к решению проблемы. Когда стресс становится действительно невыносимым, своевременное обращение за помощью к специалисту тоже совершенно необходимо.',
    4
),
(
    'Проблема старения населения',
    '随着医疗水平的提高和生育率的下降,人口老龄化已经成为许多国家共同面临的社会问题。老龄化不仅意味着劳动力人口比例的减少,还给养老保障体系和医疗资源带来了巨大的压力。为了应对这一挑战,一些国家开始延迟退休年龄,鼓励老年人继续参与社会活动;另一些国家则大力发展养老产业,完善社区养老和居家养老服务。与此同时,如何转变社会观念,让老年人得到应有的尊重和关怀,也是不容忽视的重要议题。可以说,妥善解决人口老龄化问题,关系到每一个人未来的生活质量。',
    'Suízhe yīliáo shuǐpíng de tígāo hé shēngyùlǜ de xiàjiàng, rénkǒu lǎolínghuà yǐjīng chéngwéi xǔduō guójiā gòngtóng miànlín de shèhuì wèntí. Lǎolínghuà bùjǐn yìwèizhe láodònglì rénkǒu bǐlì de jiǎnshǎo, hái gěi yǎnglǎo bǎozhàng tǐxì hé yīliáo zīyuán dàiláile jùdà de yālì. Wèile yìngduì zhè yí tiǎozhàn, yìxiē guójiā kāishǐ yánchí tuìxiū niánlíng, gǔlì lǎoniánrén jìxù cānyù shèhuì huódòng; lìng yìxiē guójiā zé dàlì fāzhǎn yǎnglǎo chǎnyè, wánshàn shèqū yǎnglǎo hé jūjiā yǎnglǎo fúwù. Yǔcǐtóngshí, rúhé zhuǎnbiàn shèhuì guānniàn, ràng lǎoniánrén dédào yīngyǒu de zūnzhòng hé guānhuái, yě shì bùróng hūshì de zhòngyào yìtí. Kěyǐ shuō, tuǒshàn jiějué rénkǒu lǎolínghuà wèntí, guānxì dào měi yí gè rén wèilái de shēnghuó zhìliàng.',
    'С повышением уровня медицины и снижением рождаемости старение населения уже стало социальной проблемой, с которой сталкиваются многие страны. Старение населения означает не только сокращение доли трудоспособного населения, но и создаёт огромное давление на систему пенсионного обеспечения и медицинские ресурсы. Чтобы справиться с этим вызовом, некоторые страны начали откладывать возраст выхода на пенсию, поощряя пожилых людей продолжать участвовать в общественной жизни; другие страны активно развивают индустрию ухода за пожилыми, совершенствуя услуги общественного и домашнего ухода. В то же время вопрос о том, как изменить общественные представления, чтобы пожилые люди получали должное уважение и заботу, также является важной темой, которую нельзя игнорировать. Можно сказать, что надлежащее решение проблемы старения населения касается качества жизни каждого человека в будущем.',
    5
),
(
    'Традиционная китайская медицина',
    '中医作为中国传统文化的重要组成部分,已经有几千年的历史。与西医不同,中医强调"整体观念"和"辨证施治",认为人体是一个有机的整体,治疗疾病不能只关注局部症状,而要从根本上调理身体的平衡。针灸、推拿、中药等,都是中医常用的治疗手段。近年来,随着人们健康意识的提高,越来越多的人开始重新认识中医的价值,不少西方国家也逐渐接受并研究中医疗法。当然,中医也面临着如何与现代科学更好结合、实现标准化和国际化的挑战。',
    'Zhōngyī zuòwéi Zhōngguó chuántǒng wénhuà de zhòngyào zǔchéng bùfen, yǐjīng yǒu jǐ qiān nián de lìshǐ. Yǔ xīyī bùtóng, Zhōngyī qiángdiào "zhěngtǐ guānniàn" hé "biànzhèng shīzhì", rènwéi réntǐ shì yí gè yǒujī de zhěngtǐ, zhìliáo jíbìng bù néng zhǐ guānzhù júbù zhèngzhuàng, ér yào cóng gēnběn shàng tiáolǐ shēntǐ de pínghéng. Zhēnjiǔ, tuīná, zhōngyào děng, dōu shì Zhōngyī chángyòng de zhìliáo shǒuduàn. Jìnnián lái, suízhe rénmen jiànkāng yìshí de tígāo, yuè lái yuè duō de rén kāishǐ chóngxīn rènshi Zhōngyī de jiàzhí, bù shǎo xīfāng guójiā yě zhújiàn jiēshòu bìng yánjiū Zhōngyī liáofǎ. Dāngrán, Zhōngyī yě miànlínzhe rúhé yǔ xiàndài kēxué gèng hǎo jiéhé, shíxiàn biāozhǔnhuà hé guójìhuà de tiǎozhàn.',
    'Китайская медицина как важная часть традиционной китайской культуры насчитывает уже несколько тысяч лет истории. В отличие от западной медицины, китайская медицина подчёркивает «целостный подход» и «лечение согласно диагностике по синдромам», полагая, что человеческое тело — это единый органический организм, и лечение болезни не может фокусироваться только на локальных симптомах, а должно в корне регулировать баланс организма. Иглоукалывание, массаж туйна, китайские травы — всё это распространённые методы лечения в китайской медицине. В последние годы, с ростом осознанности людей о здоровье, всё больше людей начинают заново открывать для себя ценность китайской медицины, и немало западных стран постепенно принимают и изучают методы китайского лечения. Конечно, китайская медицина также сталкивается с вызовом того, как лучше сочетаться с современной наукой и достичь стандартизации и интернационализации.',
    5
),
(
    'Роль социальных сетей в обществе',
    '社交媒体的兴起,彻底改变了人们获取信息和相互交流的方式。通过社交平台,人们可以随时随地分享自己的生活、观点,也能够第一时间了解世界各地发生的事情。这种便利性,极大地拉近了人与人之间的距离。然而,社交媒体也是一把双刃剑。一方面,虚假信息和谣言在网络上传播的速度极快,给社会带来了不小的困扰;另一方面,过度依赖社交媒体,也可能让人陷入信息茧房,只接触到自己认同的观点,逐渐失去客观、全面看待问题的能力。因此,理性使用社交媒体、提高媒介素养,已经成为现代人必须具备的能力之一。',
    'Shèjiāo méitǐ de xīngqǐ, chèdǐ gǎibiànle rénmen huòqǔ xìnxī hé xiānghù jiāoliú de fāngshì. Tōngguò shèjiāo píngtái, rénmen kěyǐ suíshí suídì fēnxiǎng zìjǐ de shēnghuó, guāndiǎn, yě nénggòu dìyī shíjiān liǎojiě shìjiè gèdì fāshēng de shìqing. Zhè zhǒng biànlìxìng, jídà de lājìnle rén yǔ rén zhījiān de jùlí. Rán''ér, shèjiāo méitǐ yě shì yì bǎ shuāngrènjiàn. Yì fāngmiàn, xūjiǎ xìnxī hé yáoyán zài wǎngluò shàng chuánbò de sùdù jí kuài, gěi shèhuì dàiláile bù xiǎo de kùnrǎo; lìng yì fāngmiàn, guòdù yīlài shèjiāo méitǐ, yě kěnéng ràng rén xiànrù xìnxī jiǎnfáng, zhǐ jiēchù dào zìjǐ rèntóng de guāndiǎn, zhújiàn shīqù kèguān, quánmiàn kàndài wèntí de nénglì. Yīncǐ, lǐxìng shǐyòng shèjiāo méitǐ, tígāo méijiè sùyǎng, yǐjīng chéngwéi xiàndài rén bìxū jùbèi de nénglì zhī yī.',
    'Появление социальных сетей полностью изменило способы получения информации и взаимного общения людей. Через социальные платформы люди могут в любое время и в любом месте делиться своей жизнью, взглядами, а также немедленно узнавать о событиях, происходящих по всему миру. Это удобство значительно сократило дистанцию между людьми. Однако социальные сети — это ещё и обоюдоострый меч. С одной стороны, ложная информация и слухи распространяются в сети чрезвычайно быстро, создавая немалые проблемы для общества; с другой стороны, чрезмерная зависимость от социальных сетей может привести человека в «информационный кокон», где он сталкивается только с точками зрения, которые сам разделяет, постепенно теряя способность объективно и всесторонне смотреть на проблемы. Поэтому рациональное использование социальных сетей и повышение медиаграмотности уже стали одной из необходимых компетенций современного человека.',
    5
),
(
    'Образование и творческое мышление',
    '传统的教育模式往往注重知识的灌输和标准答案的记忆,而忽视了对学生创造力和独立思考能力的培养。近年来,教育界逐渐意识到这一问题,越来越多的学校开始尝试改革教学方法,鼓励学生提出问题、进行讨论,而不是被动地接受知识。有的学校还引入了项目式学习,让学生通过完成实际项目来锻炼解决问题的能力。研究表明,富有创造力的学生往往在面对未知挑战时表现得更加从容自信。因此,如何在教育中平衡基础知识的传授与创造力的培养,是当今教育改革需要不断探索的方向。',
    'Chuántǒng de jiàoyù móshì wǎngwǎng zhùzhòng zhīshi de guànshū hé biāozhǔn dá''àn de jìyì, ér hūshìle duì xuésheng chuàngzàolì hé dúlì sīkǎo nénglì de péiyǎng. Jìnnián lái, jiàoyùjiè zhújiàn yìshí dào zhè yí wèntí, yuè lái yuè duō de xuéxiào kāishǐ chángshì gǎigé jiàoxué fāngfǎ, gǔlì xuésheng tíchū wèntí, jìnxíng tǎolùn, ér bú shì bèidòng de jiēshòu zhīshi. Yǒude xuéxiào hái yǐnrùle xiàngmùshì xuéxí, ràng xuésheng tōngguò wánchéng shíjì xiàngmù lái duànliàn jiějué wèntí de nénglì. Yánjiū biǎomíng, fùyǒu chuàngzàolì de xuésheng wǎngwǎng zài miànduì wèizhī tiǎozhàn shí biǎoxiàn de gèngjiā cóngróng zìxìn. Yīncǐ, rúhé zài jiàoyù zhōng pínghéng jīchǔ zhīshi de chuánshòu yǔ chuàngzàolì de péiyǎng, shì dāngjīn jiàoyù gǎigé xūyào bùduàn tànsuǒ de fāngxiàng.',
    'Традиционная модель образования часто делает упор на вливание знаний и запоминание стандартных ответов, пренебрегая развитием у учащихся творческих способностей и умения самостоятельно мыслить. В последние годы сфера образования постепенно осознаёт эту проблему, и всё больше школ начинают пробовать реформировать методы преподавания, поощряя учеников задавать вопросы и вести обсуждения вместо пассивного получения знаний. В некоторых школах также ввели проектное обучение, позволяющее ученикам развивать навыки решения проблем через выполнение реальных проектов. Исследования показывают, что творческие ученики, как правило, ведут себя более уверенно и спокойно при столкновении с неизвестными вызовами. Поэтому вопрос о том, как сбалансировать в образовании передачу базовых знаний и развитие творческих способностей — это направление, которое современная реформа образования должна постоянно исследовать.',
    5
),
(
    'Экологические проблемы городов',
    '随着城市化进程的加快,越来越多的人涌入城市,城市规模不断扩大,随之而来的是一系列环境问题:空气污染、水资源短缺、垃圾处理困难等。这些问题不仅影响居民的生活质量,也对城市的可持续发展构成了严重威胁。为了解决这些问题,许多城市开始推广绿色出行,鼓励市民使用公共交通工具或骑自行车代替私家车;同时,加大对可再生能源的投入,减少对化石燃料的依赖。此外,垃圾分类制度的推行,也在逐步改善城市的环境卫生状况。建设一个宜居、环保的城市,需要政府、企业和每一位市民的共同努力。',
    'Suízhe chéngshìhuà jìnchéng de jiākuài, yuè lái yuè duō de rén yǒngrù chéngshì, chéngshì guīmó búduàn kuòdà, suízhī érlái de shì yíxìliè huánjìng wèntí: kōngqì wūrǎn, shuǐ zīyuán duǎnquē, lājī chǔlǐ kùnnan děng. Zhèxiē wèntí bùjǐn yǐngxiǎng jūmín de shēnghuó zhìliàng, yě duì chéngshì de kě chíxù fāzhǎn gòuchéngle yánzhòng wēixié. Wèile jiějué zhèxiē wèntí, xǔduō chéngshì kāishǐ tuīguǎng lǜsè chūxíng, gǔlì shìmín shǐyòng gōnggòng jiāotōng gōngjù huò qí zìxíngchē dàitì sījiāchē; tóngshí, jiādà duì kězàishēng néngyuán de tóurù, jiǎnshǎo duì huàshí ránliào de yīlài. Cǐwài, lājī fēnlèi zhìdù de tuīxíng, yě zài zhúbù gǎishàn chéngshì de huánjìng wèishēng zhuàngkuàng. Jiànshè yí gè yíjū, huánbǎo de chéngshì, xūyào zhèngfǔ, qǐyè hé měi yí wèi shìmín de gòngtóng nǔlì.',
    'С ускорением процесса урбанизации всё больше людей стекается в города, масштабы городов постоянно расширяются, а вместе с этим приходит ряд экологических проблем: загрязнение воздуха, нехватка водных ресурсов, трудности с переработкой мусора и другие. Эти проблемы не только влияют на качество жизни жителей, но и представляют серьёзную угрозу устойчивому развитию городов. Чтобы решить эти проблемы, многие города начинают продвигать «зелёные» способы передвижения, поощряя жителей пользоваться общественным транспортом или ездить на велосипеде вместо личного автомобиля; одновременно увеличиваются вложения в возобновляемые источники энергии, снижается зависимость от ископаемого топлива. Кроме того, внедрение системы сортировки мусора постепенно улучшает санитарное состояние городской среды. Строительство удобного для жизни, экологичного города требует совместных усилий правительства, предприятий и каждого жителя.',
    5
),
(
    'Философия срединного пути',
    '"中庸之道"是中国传统哲学思想的重要组成部分,强调的是凡事不偏不倚、恰到好处。这句话最先出自儒家经典《中庸》,其核心思想并非教人消极妥协、不思进取,而是强调在处理问题时应该保持一种理性、平和的态度,避免走极端。无论是为人处世,还是治国理政,中庸之道都提倡在对立的两端之间寻找一个恰当的平衡点。在当今这个信息爆炸、观点两极分化日益严重的时代,重新审视中庸之道的智慧,或许能够为我们提供一种更加理性、包容的思考方式。',
    '"Zhōngyōng zhī dào" shì Zhōngguó chuántǒng zhéxué sīxiǎng de zhòngyào zǔchéng bùfen, qiángdiào de shì fánshì bù piān bù yǐ, qiàdàohǎochù. Zhè jù huà zuìxiān chūzì Rújiā jīngdiǎn "Zhōngyōng", qí héxīn sīxiǎng bìngfēi jiào rén xiāojí tuǒxié, bù sī jìnqǔ, ér shì qiángdiào zài chǔlǐ wèntí shí yīnggāi bǎochí yì zhǒng lǐxìng, pínghé de tàidù, bìmiǎn zǒu jíduān. Wúlùn shì wéirén chǔshì, háishi zhìguó lǐzhèng, Zhōngyōng zhī dào dōu tíchàng zài duìlì de liǎng duān zhījiān xúnzhǎo yí gè qiàdàng de pínghéngdiǎn. Zài dāngjīn zhè ge xìnxī bàozhà, guāndiǎn liǎngjí fēnhuà rìyì yánzhòng de shídài, chóngxīn shěnshì Zhōngyōng zhī dào de zhìhuì, huòxǔ nénggòu wèi wǒmen tígōng yì zhǒng gèngjiā lǐxìng, bāoróng de sīkǎo fāngshì.',
    '«Учение о срединном пути» — важная часть традиционной китайской философской мысли, подчёркивающая, что во всём нужно избегать крайностей и действовать в самый раз. Это выражение впервые встречается в конфуцианском каноне «Чжун юн», и его суть заключается вовсе не в том, чтобы учить людей пассивному компромиссу и отказу от стремления вперёд, а в том, чтобы подчеркнуть необходимость сохранять рациональное, спокойное отношение при решении проблем, избегая крайностей. Будь то в отношениях между людьми или в управлении государством, учение о срединном пути всегда призывает искать подходящую точку баланса между двумя противоположными крайностями. В нынешнюю эпоху информационного взрыва и всё более серьёзной поляризации взглядов новое переосмысление мудрости срединного пути, возможно, способно предложить нам более рациональный и толерантный способ мышления.',
    6
),
(
    'Искусство каллиграфии',
    '书法作为中国传统艺术的瑰宝之一,不仅是一种书写文字的技艺,更承载着深厚的文化内涵和哲学思想。从甲骨文、篆书到楷书、行书、草书,汉字的书写形式在漫长的历史演变中不断丰富发展,形成了独具特色的艺术体系。练习书法讲究"心手合一",要求书写者在运笔的过程中保持内心的平静与专注,一撇一捺之间,往往能够体现出书写者的性格、修养乃至精神境界。在快节奏的现代社会,越来越多的人重新拿起毛笔练习书法,不仅是为了传承这门古老的艺术,更是为了在喧嚣中寻找一片心灵的净土。',
    'Shūfǎ zuòwéi Zhōngguó chuántǒng yìshù de guībǎo zhī yī, bùjǐn shì yì zhǒng shūxiě wénzì de jìyì, gèng chéngzàizhe shēnhòu de wénhuà nèihán hé zhéxué sīxiǎng. Cóng jiǎgǔwén, zhuànshū dào kǎishū, xíngshū, cǎoshū, Hànzì de shūxiě xíngshì zài màncháng de lìshǐ yǎnbiàn zhōng búduàn fēngfù fāzhǎn, xíngchéngle dú jù tèsè de yìshù tǐxì. Liànxí shūfǎ jiǎngjiu "xīn shǒu hé yī", yāoqiú shūxiězhě zài yùnbǐ de guòchéng zhōng bǎochí nèixīn de píngjìng yǔ zhuānzhù, yì piě yí nà zhījiān, wǎngwǎng nénggòu tǐxiàn chū shūxiězhě de xìnggé, xiūyǎng nǎizhì jīngshén jìngjiè. Zài kuài jiézòu de xiàndài shèhuì, yuè lái yuè duō de rén chóngxīn ná qǐ máobǐ liànxí shūfǎ, bùjǐn shì wèile chuánchéng zhè mén gǔlǎo de yìshù, gèng shì wèile zài xuānxiāo zhōng xúnzhǎo yí piàn xīnlíng de jìngtǔ.',
    'Каллиграфия как одно из сокровищ традиционного китайского искусства — это не просто техника написания иероглифов, а нечто, несущее в себе глубокий культурный смысл и философскую мысль. От цзягувэнь (гадательных надписей на костях), чжуаньшу до кайшу, синшу, цаошу — формы написания китайских иероглифов непрерывно обогащались и развивались на протяжении долгой исторической эволюции, сформировав уникальную художественную систему. Практика каллиграфии требует «единства сердца и руки»: пишущий должен в процессе движения кисти сохранять внутреннее спокойствие и сосредоточенность, и в каждом штрихе часто можно увидеть характер, воспитанность и даже духовный уровень пишущего. В быстро меняющемся современном обществе всё больше людей вновь берут в руки кисть для занятий каллиграфией — не только чтобы передать это древнее искусство, но и чтобы найти островок душевного покоя среди суеты.',
    6
),
(
    'Значение традиций в современном обществе',
    '在全球化和现代化浪潮的冲击下,传统文化的传承正面临前所未有的挑战。一方面,年轻一代对传统节日、民俗礼仪的了解越来越少,许多传统技艺也因为缺乏传承人而濒临失传;另一方面,商业化的过度包装,也使得一些传统文化在传播过程中失去了原本的内涵,沦为单纯的表演和消费符号。然而,传统并非一成不变的教条,而是一个民族在漫长历史中积累下来的智慧结晶,其中蕴含着解决当下问题的宝贵启示。如何在保持传统精髓的同时,赋予其符合时代需求的新的表现形式,是每一个文化传承者都需要思考的课题。',
    'Zài quánqiúhuà hé xiàndàihuà làngcháo de chōngjī xià, chuántǒng wénhuà de chuánchéng zhèng miànlín qiánsuǒwèiyǒu de tiǎozhàn. Yì fāngmiàn, niánqīng yídài duì chuántǒng jiérì, mínsú lǐyí de liǎojiě yuè lái yuè shǎo, xǔduō chuántǒng jìyì yě yīnwèi quēfá chuánchéngrén ér bīnlín shīchuán; lìng yì fāngmiàn, shāngyèhuà de guòdù bāozhuāng, yě shǐde yìxiē chuántǒng wénhuà zài chuánbò guòchéng zhōng shīqùle yuánběn de nèihán, lúnwéi dānchún de biǎoyǎn hé xiāofèi fúhào. Rán''ér, chuántǒng bìngfēi yìchéngbùbiàn de jiàotiáo, ér shì yí gè mínzú zài màncháng lìshǐ zhōng jīlěi xiàlái de zhìhuì jiéjīng, qízhōng yùnhánzhe jiějué dāngxià wèntí de bǎoguì qǐshì. Rúhé zài bǎochí chuántǒng jīngsuǐ de tóngshí, fùyǔ qí fúhé shídài xūqiú de xīn de biǎoxiàn xíngshì, shì měi yí gè wénhuà chuánchéngzhě dōu xūyào sīkǎo de kètí.',
    'Под натиском волн глобализации и модернизации передача традиционной культуры сталкивается с беспрецедентными вызовами. С одной стороны, молодое поколение всё меньше знает о традиционных праздниках и народных обычаях, многие традиционные ремёсла оказываются на грани исчезновения из-за отсутствия преемников; с другой стороны, чрезмерная коммерческая упаковка приводит к тому, что некоторые элементы традиционной культуры в процессе распространения теряют изначальный смысл, превращаясь в простое представление и символ потребления. Однако традиция — это не застывшая раз и навсегда догма, а кристаллизация мудрости, накопленной народом за долгую историю, в которой содержатся ценные подсказки для решения нынешних проблем. Вопрос о том, как, сохраняя суть традиции, придать ей новые формы выражения, соответствующие требованиям времени, — задача, над которой должен размышлять каждый хранитель культуры.',
    6
),
(
    'Глобализация и культурная идентичность',
    '全球化进程的加速,使得不同国家和地区之间的经济、文化交流日益频繁,世界似乎变得越来越"小"。然而,伴随着全球化而来的,还有一个不容忽视的问题——文化同质化。当好莱坞电影、西方快餐连锁店遍布世界各个角落时,一些本土文化和语言正在悄然消失。面对这一现象,如何在拥抱全球化带来的便利与机遇的同时,保护并传承本民族独特的文化身份,成为许多国家不得不认真对待的课题。事实上,真正健康的全球化,不应该是一种文化对另一种文化的取代,而应该是多元文化在相互尊重的基础上共存与交融。',
    'Quánqiúhuà jìnchéng de jiāsù, shǐde bùtóng guójiā hé dìqū zhījiān de jīngjì, wénhuà jiāoliú rìyì pínfán, shìjiè sìhū biàn de yuè lái yuè "xiǎo". Rán''ér, bànsuízhe quánqiúhuà ér lái de, hái yǒu yí gè bùróng hūshì de wèntí — wénhuà tóngzhìhuà. Dāng Hǎoláiwū diànyǐng, xīfāng kuàicān liánsuǒdiàn biànbù shìjiè gège jiǎoluò shí, yìxiē běntǔ wénhuà hé yǔyán zhèngzài qiāorán xiāoshī. Miànduì zhè yí xiànxiàng, rúhé zài yōngbào quánqiúhuà dàilái de biànlì yǔ jīyù de tóngshí, bǎohù bìng chuánchéng běn mínzú dútè de wénhuà shēnfèn, chéngwéi xǔduō guójiā bùdébù rènzhēn duìdài de kètí. Shìshí shàng, zhēnzhèng jiànkāng de quánqiúhuà, bù yīnggāi shì yì zhǒng wénhuà duì lìng yì zhǒng wénhuà de qǔdài, ér yīnggāi shì duōyuán wénhuà zài xiānghù zūnzhòng de jīchǔ shàng gòngcún yǔ jiāoróng.',
    'Ускорение процесса глобализации привело к тому, что экономические и культурные обмены между разными странами и регионами становятся всё более частыми, и мир, кажется, становится всё «меньше». Однако вместе с глобализацией приходит и проблема, которую нельзя игнорировать — культурная гомогенизация. Пока голливудские фильмы и западные сети быстрого питания распространяются по всем уголкам мира, некоторые местные культуры и языки незаметно исчезают. Перед лицом этого явления вопрос о том, как, пользуясь удобствами и возможностями, которые несёт глобализация, одновременно защищать и передавать уникальную культурную идентичность своего народа, становится темой, к которой многим странам приходится относиться серьёзно. На самом деле подлинно здоровая глобализация не должна быть заменой одной культуры другой, а должна представлять собой сосуществование и взаимопроникновение многообразных культур на основе взаимного уважения.',
    6
),
(
    'Взаимоотношения человека и природы',
    '自古以来,人类与自然的关系就是一个永恒的话题。在农业社会,人们敬畏自然,依赖自然的馈赠维持生存;进入工业时代以后,人类凭借科技的进步,开始大规模地改造自然、征服自然,却也因此付出了沉重的代价——森林锐减、物种灭绝、气候变暖等问题接踵而至。这些生态危机让人类逐渐意识到,人与自然并非征服与被征服的关系,而应该是相互依存、和谐共生的关系。中国古代哲学中"天人合一"的思想,强调人应当顺应自然规律,而非凌驾于自然之上,这一古老的智慧,对于今天应对生态危机、实现可持续发展,依然具有重要的启发意义。',
    'Zìgǔ yǐlái, rénlèi yǔ zìrán de guānxì jiùshì yí gè yǒnghéng de huàtí. Zài nóngyè shèhuì, rénmen jìngwèi zìrán, yīlài zìrán de kuìzèng wéichí shēngcún; jìnrù gōngyè shídài yǐhòu, rénlèi píngjiè kējì de jìnbù, kāishǐ dàguīmó de gǎizào zìrán, zhēngfú zìrán, què yě yīncǐ fùchūle chénzhòng de dàijià — sēnlín ruìjiǎn, wùzhǒng mièjué, qìhòu biànnuǎn děng wèntí jiēzhǒng''érzhì. Zhèxiē shēngtài wēijī ràng rénlèi zhújiàn yìshí dào, rén yǔ zìrán bìngfēi zhēngfú yǔ bèi zhēngfú de guānxì, ér yīnggāi shì xiānghù yīcún, héxié gòngshēng de guānxì. Zhōngguó gǔdài zhéxué zhōng "tiān rén hé yī" de sīxiǎng, qiángdiào rén yīngdāng shùnyìng zìrán guīlǜ, ér fēi língjiàyú zìrán zhī shàng, zhè yí gǔlǎo de zhìhuì, duìyú jīntiān yìngduì shēngtài wēijī, shíxiàn kě chíxù fāzhǎn, yīrán jùyǒu zhòngyào de qǐfā yìyì.',
    'С древних времён отношения между человеком и природой были вечной темой. В аграрном обществе люди почитали природу, полагаясь на её дары для выживания; с наступлением индустриальной эпохи человечество, опираясь на технологический прогресс, начало масштабно преобразовывать природу, покорять её, но за это пришлось заплатить тяжёлую цену — сокращение лесов, вымирание видов, потепление климата и другие проблемы, следующие одна за другой. Эти экологические кризисы постепенно дали человечеству понять, что отношения между человеком и природой — это не отношения покорителя и покорённого, а должны быть отношениями взаимозависимости и гармоничного сосуществования. Мысль о «единстве неба и человека» в древнекитайской философии подчёркивает, что человек должен следовать законам природы, а не возвышаться над ней — эта древняя мудрость и сегодня имеет важное вдохновляющее значение для преодоления экологического кризиса и достижения устойчивого развития.',
    6
);
